declare const $: any;
declare const Slider: any;
declare const document: any;
declare function swal(message: string): void;

// TODO: import these from appropriate modules
declare const client: any;
import { governmentMaxRate as government_max_rate } from "../data/government";
declare const governments: any;
import { packet_player_rates } from "../net/packetConstants"; // TODO: adjust import path and name
import { send_request } from "../net/connection"; // TODO: adjust import path and name
import { isSmallScreen as is_small_screen } from "../utils/helpers"; // TODO: adjust import path and name
import { clientIsObserver as client_is_observer } from '../client/clientState';
import { getCurrentBulbsOutput as get_current_bulbs_output } from '../data/tech';

export let s_tax: any = null;
export let s_lux: any = null;
export let s_sci: any = null;

export let tax: number;
export let sci: number;
export let lux: number;

export let maxrate: number = 80;
export let freeze: boolean = false;
export let government_list: any;
export let current_government: any;

export function show_tax_rates_dialog(): void {
  const id = "#rates_dialog";
  $(id).remove();
  $("<div id='rates_dialog'></div>").appendTo("div#game_page");

  const dhtml = "<h2>Select tax, luxury and science rates</h2>"
    + "<form name='rates'><table border='0' style='color: #ffffff;'>"
    + "<tr> <td><span>Tax:</td> <td> <div class='slider' id='slider-tax' tabIndex='1'></div>"
    + "</td><td>"
    + "<div id='tax_result' style='float:left;'></div></td>"
    + "<td> <INPUT TYPE='CHECKBOX' NAME='lock'>Lock</td></tr>"
    + "<tr><td>Luxury:</td><td><div class='slider' id='slider-lux' tabIndex='1'></div>"
    + "</td><td> <div id='lux_result' style='float:left;'></div>"
    + "</td><td><INPUT TYPE='CHECKBOX' NAME='lock'>Lock</td></tr>"
    + "<tr><td>Science:</td><td><div class='slider' id='slider-sci' tabIndex='1'></div>"
    + "</td><td><div id='sci_result' style='float:left;'></div>"
    + "</td><td><INPUT TYPE='CHECKBOX' NAME='lock'>Lock</td></tr>"
    + "</table></form>"
    + "<div id='max_tax_rate' style='margin:10px;'>"
    + "</div><div style='margin:10px;'>"
    + "Net income: <span id='income_info'></span><br>"
    + "Research: <span id='bulbs_info'></span></div>";

  $(id).html(dhtml);

  $(id).attr("title", "Change your tax rates!");
  $(id).dialog({
    bgiframe: true,
    modal: true,
    width: is_small_screen() ? "90%" : "40%",
    buttons: {
      "Close": function() {
        $("#rates_dialog").dialog('close');
      }
    }
  });

  update_rates_dialog();
}

export function update_rates_dialog(): void {
  if (client_is_observer()) return;

  maxrate = government_max_rate(client.conn.playing['government']);

  $("#slider-tax").html("<input class='slider-input' id='slider-tax-input' name='slider-tax-input'/>");
  $("#slider-lux").html("<input class='slider-input' id='slider-lux-input' name='slider-lux-input'/>");
  $("#slider-sci").html("<input class='slider-input' id='slider-sci-input' name='slider-sci-input'/>");

  create_rates_dialog(client.conn.playing['tax'],
                      client.conn.playing['luxury'],
                      client.conn.playing['science'], maxrate);

  const govt = governments[client.conn.playing['government']];

  $("#max_tax_rate").html("<i>" + govt['name'] + " max rate: " + maxrate + "</i>");
  update_net_income();
  update_net_bulbs();
}

export function update_net_income(): void {
  let net_income: string | number = client.conn.playing['expected_income'];
  if (client.conn.playing['expected_income'] > 0) {
    net_income = "+" + client.conn.playing['expected_income'];
  }
  $("#income_info").html(net_income);
}

export function update_net_bulbs(bulbs?: number): void {
  if (bulbs === undefined) {
    const cbo = get_current_bulbs_output();
    bulbs = cbo.self_bulbs - cbo.self_upkeep;
  }
  const bulbsStr: string = bulbs > 0 ? "+" + bulbs : String(bulbs);
  $("#bulbs_info").html(bulbsStr);
}

export function create_rates_dialog(taxVal: number, luxVal: number, sciVal: number, max: number): void {
  s_tax = new Slider(document.getElementById("slider-tax"),
                   document.getElementById("slider-tax-input"));
  s_tax.setValue(taxVal);
  s_tax.setMaximum(max);
  s_tax.setMinimum(0);
  s_tax.setBlockIncrement(10);
  s_tax.setUnitIncrement(10);
  s_tax.onchange = update_tax_rates;

  s_lux = new Slider(document.getElementById("slider-lux"),
                   document.getElementById("slider-lux-input"));
  s_lux.setValue(luxVal);
  s_lux.setMaximum(max);
  s_lux.setMinimum(0);
  s_lux.setBlockIncrement(10);
  s_lux.setUnitIncrement(10);
  s_lux.onchange = update_lux_rates;

  s_sci = new Slider(document.getElementById("slider-sci"),
                   document.getElementById("slider-sci-input"));
  s_sci.setValue(sciVal);
  s_sci.setMaximum(max);
  s_sci.setMinimum(0);
  s_sci.setBlockIncrement(10);
  s_sci.setUnitIncrement(10);
  s_sci.onchange = update_sci_rates;

  maxrate = max;

  update_rates_labels();
}

export function update_rates_labels(): void {
  tax = s_tax.getValue();
  lux = s_lux.getValue();
  sci = s_sci.getValue();

  $("#tax_result").html(tax + "%");
  $("#lux_result").html(lux + "%");
  $("#sci_result").html(sci + "%");
}

export function update_tax_rates(): void {
  if (freeze) return;
  freeze = true;

  if (s_tax.getValue() % 10 !== 0) s_tax.setValue(s_tax.getValue() - (s_tax.getValue() % 10));
  if (s_lux.getValue() % 10 !== 0) s_lux.setValue(s_lux.getValue() - (s_lux.getValue() % 10));
  if (s_sci.getValue() % 10 !== 0) s_sci.setValue(s_sci.getValue() - (s_sci.getValue() % 10));

  const lock_lux: boolean = document.rates.lock[1].checked;
  const lock_sci: boolean = document.rates.lock[2].checked;

  tax = s_tax.getValue();
  lux = s_lux.getValue();
  sci = s_sci.getValue();

  if (tax + lux + sci !== 100 && lock_lux === false) {
    lux = Math.min(Math.max(100 - tax - sci, 0), maxrate);
  }
  if (tax + lux + sci !== 100 && lock_sci === false) {
    sci = Math.min(Math.max(100 - lux - tax, 0), maxrate);
  }

  if (tax + lux + sci !== 100) {
    s_tax.setValue(100 - lux - sci);
    freeze = false;
    return;
  }

  s_tax.setValue(tax);
  s_lux.setValue(lux);
  s_sci.setValue(sci);

  $("#tax_result").html(tax + "%");
  $("#lux_result").html(lux + "%");
  $("#sci_result").html(sci + "%");

  freeze = false;
  submit_player_rates();
}

